import React, { useState, useRef, useEffect } from 'react';
import { Upload, File, X, CheckCircle, AlertCircle } from 'lucide-react';

const DocumentUpload = () => {
  const [formData, setFormData] = useState({
    employeeId: '',
    employeeName: '',
    store: '',
    documentType: '',
    issueDate: '',
    expiryDate: '',
    remarks: ''
  });
  const [files, setFiles] = useState([]);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [dragActive, setDragActive] = useState(false);
  const [employees] = useState([
    { id: 'EMP001', name: 'John Doe', store: 'Store 1' },
    { id: 'EMP002', name: 'Jane Smith', store: 'Store 2' },
    { id: 'EMP003', name: 'Bob Johnson', store: 'Store 3' },
    { id: 'EMP004', name: 'Alice Williams', store: 'Store 1' },
    { id: 'EMP005', name: 'Charlie Brown', store: 'Store 4' }
  ]);
  const [documentTypes] = useState([
    'ID Proof',
    'Driving License',
    'Medical Certificate',
    'Training Certificate',
    'Employment Contract',
    'Educational Certificate',
    'Address Proof',
    'Police Verification'
  ]);
  const [uploadResults, setUploadResults] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [errors, setErrors] = useState({});
  const fileInputRef = useRef(null);

  const stores = [
    'Store 1', 'Store 2', 'Store 3', 'Store 4', 'Store 5',
    'Store 6', 'Store 7', 'Store 8', 'Store 9', 'Store 10'
  ];

  useEffect(() => {
    const today = new Date();
    const todayString = today.toISOString().split('T')[0];
    setFormData(prev => ({
      ...prev,
      issueDate: todayString
    }));
  }, []);

  const getTodayDate = () => {
    const today = new Date();
    return today.toISOString().split('T')[0];
  };

  const getMinExpiryDate = () => {
    if (!formData.issueDate) {
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      return tomorrow.toISOString().split('T')[0];
    }
    
    const issueDate = new Date(formData.issueDate);
    issueDate.setDate(issueDate.getDate() + 1);
    return issueDate.toISOString().split('T')[0];
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
    
    if (name === 'employeeId' && value) {
      const selectedEmployee = employees.find(emp => emp.id === value);
      if (selectedEmployee) {
        setFormData(prev => ({
          ...prev,
          employeeId: value,
          employeeName: selectedEmployee.name,
          store: selectedEmployee.store || prev.store
        }));
        return;
      }
    }
    
    if (name === 'issueDate') {
      setFormData(prev => ({
        ...prev,
        issueDate: value,
        expiryDate: ''
      }));
      return;
    }
    
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFileSelect(e.dataTransfer.files);
    }
  };

  const handleFileSelect = (selectedFiles) => {
    if (!formData.documentType) {
      alert('Please select a document type first');
      return;
    }

    if (!formData.issueDate || !formData.expiryDate) {
      alert('Please select issue date and expiry date first');
      return;
    }

    const fileArray = Array.from(selectedFiles);
    const validTypes = ['application/pdf', 'image/jpeg', 'image/png', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
    
    const validFiles = fileArray.filter(file => {
      if (validTypes.includes(file.type)) {
        return true;
      } else {
        alert(`Invalid file type: ${file.name}. Please upload PDF, DOCX, JPG, or PNG`);
        return false;
      }
    });
    
    const newFiles = validFiles.map(file => ({
      file: file,
      documentType: formData.documentType,
      issueDate: formData.issueDate,
      expiryDate: formData.expiryDate,
      remarks: formData.remarks
    }));
    
    setFiles(prev => [...prev, ...newFiles]);
    
    if (validFiles.length > 0 && errors.files) {
      setErrors(prev => ({
        ...prev,
        files: ''
      }));
    }
  };

  const handleFileInput = (e) => {
    if (e.target.files && e.target.files.length > 0) {
      handleFileSelect(e.target.files);
      e.target.value = '';
    }
  };

  const removeFile = (index) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const validateForm = () => {
    const newErrors = {};
    
    if (!formData.employeeId) newErrors.employeeId = 'Please select an employee';
    if (!formData.employeeName) newErrors.employeeName = 'Employee name is required';
    if (!formData.store) newErrors.store = 'Please select a store';
    if (files.length === 0) newErrors.files = 'Please add at least one file to upload';
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validateForm()) {
      alert('Please fill all required fields correctly');
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);
    setShowResults(false);
    
    const results = [];
    const totalFiles = files.length;
    let successCount = 0;
    let failCount = 0;

    for (let i = 0; i < files.length; i++) {
      const fileData = files[i];
      
      try {
        await new Promise((resolve) => setTimeout(resolve, 500));
        
        successCount++;
        results.push({
          fileName: fileData.file.name,
          documentType: fileData.documentType,
          status: 'success',
          message: 'Uploaded successfully',
          documentId: `DOC${Math.floor(Math.random() * 10000)}`
        });
        
      } catch (error) {
        failCount++;
        results.push({
          fileName: fileData.file.name,
          documentType: fileData.documentType,
          status: 'error',
          message: 'Upload failed'
        });
      }
      
      setUploadProgress(Math.round(((i + 1) / totalFiles) * 100));
    }

    setIsUploading(false);
    setUploadResults(results);
    setShowResults(true);

    if (successCount === totalFiles) {
      alert(`All ${totalFiles} document(s) uploaded successfully!`);
      const todayString = getTodayDate();
      setFormData({
        employeeId: '',
        employeeName: '',
        store: '',
        documentType: '',
        issueDate: todayString,
        expiryDate: '',
        remarks: ''
      });
      setFiles([]);
      setUploadProgress(0);
      setErrors({});
      if (fileInputRef.current) fileInputRef.current.value = '';
      
      setTimeout(() => {
        setShowResults(false);
        setUploadResults([]);
      }, 5000);
    }
  };

  return (
    <div className="p-4 max-w-6xl mx-auto">
      <div className="bg-white rounded-2xl shadow-2xl overflow-hidden">
        <div className="sticky top-0 z-50 bg-gradient-to-r from-purple-600 to-purple-800 text-white p-6">
          <div className="flex items-center gap-3">
            <Upload size={28} />
            <h2 className="text-2xl font-bold">Upload Employee Documents</h2>
          </div>
        </div>

        <div className="p-6">
          {showResults && uploadResults.length > 0 && (
            <div className={`mb-6 p-4 rounded-xl border-2 ${uploadResults.every(r => r.status === 'success') ? 'bg-green-50 border-green-200' : 'bg-yellow-50 border-yellow-200'}`}>
              <h4 className="text-lg font-bold mb-3 flex items-center gap-2">
                {uploadResults.every(r => r.status === 'success') ? <CheckCircle className="text-green-600" /> : <AlertCircle className="text-yellow-600" />}
                Upload Results
              </h4>
              <div className="space-y-2">
                {uploadResults.map((result, idx) => (
                  <div key={idx} className="flex items-start gap-2 bg-white p-3 rounded-lg">
                    {result.status === 'success' ? (
                      <CheckCircle className="text-green-600 flex-shrink-0 mt-1" size={18} />
                    ) : (
                      <X className="text-red-600 flex-shrink-0 mt-1" size={18} />
                    )}
                    <div className="flex-1">
                      <div className="font-semibold">{result.fileName}</div>
                      <div className="text-sm text-gray-600">{result.documentType}</div>
                      <div className={`text-sm ${result.status === 'success' ? 'text-green-600' : 'text-red-600'}`}>
                        {result.message}
                        {result.documentId && <span className="ml-2 px-2 py-0.5 bg-blue-100 text-blue-700 rounded">ID: {result.documentId}</span>}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            <div>
              <label className="block text-sm font-semibold mb-2">
                Employee <span className="text-red-500">*</span>
              </label>
              <select
                name="employeeId"
                value={formData.employeeId}
                onChange={handleInputChange}
                className={`w-full px-4 py-2 border-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 ${errors.employeeId ? 'border-red-500' : 'border-gray-300'}`}
              >
                <option value="">Select Employee</option>
                {employees.map(emp => (
                  <option key={emp.id} value={emp.id}>
                    {emp.id} - {emp.name} ({emp.store})
                  </option>
                ))}
              </select>
              {errors.employeeId && <p className="text-red-500 text-sm mt-1">{errors.employeeId}</p>}
            </div>

            <div>
              <label className="block text-sm font-semibold mb-2">
                Employee Name <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                name="employeeName"
                value={formData.employeeName}
                readOnly
                className="w-full px-4 py-2 border-2 border-gray-300 rounded-lg bg-gray-50"
                placeholder="Auto-filled"
              />
            </div>

            <div>
              <label className="block text-sm font-semibold mb-2">
                Store <span className="text-red-500">*</span>
              </label>
              <select
                name="store"
                value={formData.store}
                onChange={handleInputChange}
                className={`w-full px-4 py-2 border-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 ${errors.store ? 'border-red-500' : 'border-gray-300'}`}
              >
                <option value="">Select Store</option>
                {stores.map(store => (
                  <option key={store} value={store}>{store}</option>
                ))}
              </select>
              {errors.store && <p className="text-red-500 text-sm mt-1">{errors.store}</p>}
            </div>

            <div>
              <label className="block text-sm font-semibold mb-2">
                Document Type <span className="text-red-500">*</span>
              </label>
              <select
                name="documentType"
                value={formData.documentType}
                onChange={handleInputChange}
                className="w-full px-4 py-2 border-2 border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
              >
                <option value="">Select Document Type</option>
                {documentTypes.map(type => (
                  <option key={type} value={type}>{type}</option>
                ))}
              </select>
              <p className="text-gray-500 text-xs mt-1">Select before adding files</p>
            </div>

            <div>
              <label className="block text-sm font-semibold mb-2">
                Issue Date <span className="text-red-500">*</span>
              </label>
              <input
                type="date"
                name="issueDate"
                value={formData.issueDate}
                onChange={handleInputChange}
                max={getTodayDate()}
                className="w-full px-4 py-2 border-2 border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
              />
              <p className="text-gray-500 text-xs mt-1">Auto-filled with today</p>
            </div>

            <div>
              <label className="block text-sm font-semibold mb-2">
                Expiry Date <span className="text-red-500">*</span>
              </label>
              <input
                type="date"
                name="expiryDate"
                value={formData.expiryDate}
                onChange={handleInputChange}
                min={getMinExpiryDate()}
                disabled={!formData.issueDate}
                className="w-full px-4 py-2 border-2 border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 disabled:bg-gray-100"
              />
              <p className="text-gray-500 text-xs mt-1">Must be after issue date</p>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-semibold mb-2">Remarks</label>
              <textarea
                name="remarks"
                value={formData.remarks}
                onChange={handleInputChange}
                rows={3}
                className="w-full px-4 py-2 border-2 border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
                placeholder="Additional notes (optional)"
              />
            </div>
          </div>

          <div className="mb-6">
            <label className="block text-sm font-semibold mb-2">
              Add Files <span className="text-red-500">*</span>
              {files.length > 0 && (
                <span className="ml-2 px-3 py-1 bg-purple-100 text-purple-700 rounded-full text-xs font-bold">
                  {files.length} file{files.length !== 1 ? 's' : ''} added
                </span>
              )}
            </label>
            
            <div
              onDragEnter={handleDrag}
              onDragLeave={handleDrag}
              onDragOver={handleDrag}
              onDrop={handleDrop}
              onClick={() => fileInputRef.current?.click()}
              className={`border-2 border-dashed rounded-xl p-6 text-center cursor-pointer transition-all ${
                dragActive ? 'border-purple-600 bg-purple-50' : files.length > 0 ? 'border-gray-300 bg-white' : 'border-gray-300 bg-gray-50'
              } ${errors.files ? 'border-red-500' : ''}`}
            >
              <input
                ref={fileInputRef}
                type="file"
                onChange={handleFileInput}
                accept=".pdf,.docx,.jpg,.jpeg,.png"
                multiple
                className="hidden"
              />
              
              {files.length > 0 ? (
                <div className="space-y-2">
                  {files.map((fileData, index) => (
                    <div key={index} className="flex items-center gap-3 bg-gray-50 border border-gray-200 rounded-lg p-3 text-left">
                      <File size={20} className="text-purple-600 flex-shrink-0" />
                      <div className="flex-1 min-w-0">
                        <div className="font-semibold text-sm truncate">{fileData.file.name}</div>
                        <div className="text-xs text-gray-600">
                          {fileData.documentType} • {(fileData.file.size / 1024).toFixed(2)} KB
                        </div>
                      </div>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          removeFile(index);
                        }}
                        className="text-red-600 hover:bg-red-50 p-1 rounded"
                      >
                        <X size={18} />
                      </button>
                    </div>
                  ))}
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      fileInputRef.current?.click();
                    }}
                    disabled={!formData.documentType || !formData.issueDate || !formData.expiryDate}
                    className="mt-3 px-4 py-2 bg-purple-100 text-purple-700 rounded-lg hover:bg-purple-200 disabled:opacity-50 disabled:cursor-not-allowed text-sm font-semibold flex items-center gap-2 mx-auto"
                  >
                    <Upload size={16} />
                    Add More Files
                  </button>
                </div>
              ) : (
                <div>
                  <Upload size={48} className="text-gray-400 mx-auto mb-3" />
                  <p className="font-semibold mb-1">Click to upload or drag and drop</p>
                  <p className="text-sm text-gray-500">PDF, DOCX, JPG, PNG (Max 10MB per file)</p>
                  {(!formData.documentType || !formData.issueDate || !formData.expiryDate) && (
                    <p className="text-sm text-yellow-600 mt-2 font-medium">
                      ⚠ Select document type, issue date, and expiry date first
                    </p>
                  )}
                </div>
              )}
            </div>
            {errors.files && <p className="text-red-500 text-sm mt-1">{errors.files}</p>}
          </div>

          {isUploading && (
            <div className="mb-6">
              <div className="flex justify-between mb-2 text-sm font-semibold">
                <span>Uploading {files.length} file(s)...</span>
                <span>{uploadProgress}%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-3 overflow-hidden">
                <div
                  className="bg-gradient-to-r from-purple-600 to-purple-800 h-full transition-all duration-300 rounded-full"
                  style={{ width: `${uploadProgress}%` }}
                />
              </div>
            </div>
          )}

          <button
            onClick={handleSubmit}
            disabled={isUploading || files.length === 0}
            className="w-full py-4 bg-gradient-to-r from-purple-600 to-purple-800 text-white rounded-xl font-bold text-lg shadow-lg hover:shadow-xl transition-all disabled:opacity-50 disabled:cursor-not-allowed hover:from-purple-700 hover:to-purple-900"
          >
            {isUploading ? 'Uploading...' : `Upload ${files.length} Document${files.length !== 1 ? 's' : ''}`}
          </button>
        </div>
      </div>
    </div>
  );
};

export default DocumentUpload;
